#pragma once

#include <cstdint>
#include <string>
#include <vector>
#include <memory>
#include <map>
#include <functional>
#include <chrono>
#include <mutex>

namespace RawrXD::Agentic::Planning {

// Execution plans generated by LLM planning
enum class PlanAction : uint8_t {
    ANALYZE_CODE = 0,
    GENERATE_CODE = 1,
    REFACTOR = 2,
    TEST = 3,
    DOCUMENT = 4,
    OPTIMIZE = 5,
    VALIDATE = 6,
    PARALLEL_EXECUTE = 7,
    WAIT_FOR_DEPENDENCY = 8,
    RESOLVE_CONFLICT = 9
};

// Plan step returned by 800B model
struct PlanStep {
    uint32_t stepId = 0;
    PlanAction action = PlanAction::ANALYZE_CODE;
    std::string actionDescription;
    std::string targetResource;      // File path, function name, etc.
    std::vector<std::string> args;   // Action parameters
    std::vector<uint32_t> priorSteps;  // Dependencies (step IDs)
    float confidenceScore = 0.0f;    // 0.0-1.0
    uint32_t estimatedDurationSeconds = 60;
    bool isParallelizable = false;
    std::string rationale;           // Why the model chose this step
};

// Execution plan from model
struct ExecutionPlan {
    uint64_t planId = 0;
    uint64_t taskId = 0;
    std::string planName;
    std::string planDescription;
    std::string modelUsed;           // Which model variant generated this
    std::vector<PlanStep> steps;
    float overallConfidence = 0.0f;  // Average of step confidences
    uint32_t estimatedTotalSeconds = 0;
    std::chrono::steady_clock::time_point createdAt;
    bool executionApproved = false;
};

// Streaming decoder state for token-by-token generation
struct StreamingDecoderState {
    uint64_t decoderInstanceId = 0;
    uint32_t currentTokenIndex = 0;
    uint32_t totalTokensGenerated = 0;
    std::string partialOutput;
    bool isComplete = false;
    std::vector<float> logits;  // Next-token probabilities
};

class ModelGuidedPlanner {
public:
    static ModelGuidedPlanner& instance();

    // Plan generation with streaming 800B model
    uint64_t generatePlan(uint64_t taskId, const std::string& taskDescription,
                         const std::vector<std::string>& contextFiles,
                         uint32_t maxPlanSteps = 20);

    // Streaming generation - get tokens one at a time
    StreamingDecoderState initializeStreamingDecoder(uint64_t taskId,
                                                     const std::string& prompt);
    bool getNextToken(StreamingDecoderState& state, std::string& token);
    bool isDecodingComplete(const StreamingDecoderState& state) const;
    void finalizeStreaming(StreamingDecoderState& state);

    // Plan retrieval & management
    ExecutionPlan getPlan(uint64_t planId) const;
    std::vector<uint64_t> getPlansForTask(uint64_t taskId) const;

    // Plan execution verification
    bool validatePlan(uint64_t planId) const;
    bool isStepDependencySatisfied(uint64_t planId, uint32_t stepId) const;

    // Adaptive planning (replan if conflicts detected)
    uint64_t replan(uint64_t originalPlanId, const std::vector<uint64_t>& failedStepIds);

    // Plan approval workflow
    void submitPlanForApproval(uint64_t planId, const std::string& reviewComments);
    bool approvePlan(uint64_t planId, const std::string& approverName);
    bool rejectPlan(uint64_t planId, const std::string& rejectionReason);

    // Statistics & monitoring
    struct PlanningStats {
        uint64_t totalPlansGenerated = 0;
        uint64_t successfulPlans = 0;
        uint64_t failedPlans = 0;
        float averageConfidenceScore = 0.0f;
        uint32_t averagePlanSteps = 0;
        uint64_t totalTokensGenerated = 0;  // From 800B model
        std::chrono::milliseconds averagePlanGenerationTime;
    };
    PlanningStats getStatistics() const;

private:
    ModelGuidedPlanner();
    ~ModelGuidedPlanner();
    ModelGuidedPlanner(const ModelGuidedPlanner&) = delete;
    ModelGuidedPlanner& operator=(const ModelGuidedPlanner&) = delete;

    // Internal state
    struct PlanRecord {
        uint64_t planId;
        ExecutionPlan plan;
        std::chrono::steady_clock::time_point generatedAt;
        bool executionStarted = false;
        std::vector<uint32_t> completedSteps;
    };

    mutable std::mutex plannerMutex_;
    std::map<uint64_t, PlanRecord> plans_;
    std::map<uint64_t, std::vector<uint64_t>> taskPlans_;  // Task -> Plans
    std::map<uint64_t, StreamingDecoderState> activeDecoders_;

    uint64_t nextPlanId_ = 10000;
    uint64_t nextDecoderId_ = 1;

    // Model interaction
    void invoke_model_for_planning(uint64_t taskId, const std::string& prompt,
                                  ExecutionPlan& outPlan);
    void parse_plan_from_model_output(const std::string& modelOutput,
                                      ExecutionPlan& outPlan);
};

}  // namespace RawrXD::Agentic::Planning
